command:
// ======================================
// Roguelike 抽取点数管理器
// ======================================
// 打开抽取点数管理面板，GM可以管理通用点数和特定宏点数。
// 需要先在模块设置 → Roguelike 配置中启用抽取点数系统。
// ======================================

const mod = game.modules.get('ai-pf2e-assistant');
if (!mod?.api?.roguelikeDrawPoints?.openManager) {
  ui.notifications.warn('Roguelike 抽取点数管理器不可用，请确认模块已启用');
} else {
  mod.api.roguelikeDrawPoints.openManager();
}
